import React, { useState } from "react";

function Dashboard() {
  // Dummy data (backend later replace chestham)
  const [enquiries, setEnquiries] = useState([
    {
      id: 1,
      name: "Ravi Kumar",
      phone: "9876543210",
      location: "LB Nagar",
      service: "Interior Painting",
      status: "New",
    },
    {
      id: 2,
      name: "Suresh",
      phone: "9123456789",
      location: "Uppal",
      service: "Waterproofing",
      status: "Contacted",
    },
  ]);

  const updateStatus = (id, newStatus) => {
    setEnquiries(
      enquiries.map((item) =>
        item.id === id ? { ...item, status: newStatus } : item
      )
    );
  };

  return (
    <div className="dashboard">
      <h2>Client Enquiries</h2>

      <table>
        <thead>
          <tr>
            <th>Name</th>
            <th>Phone</th>
            <th>Location</th>
            <th>Service</th>
            <th>Status</th>
          </tr>
        </thead>

        <tbody>
          {enquiries.map((e) => (
            <tr key={e.id}>
              <td>{e.name}</td>
              <td>{e.phone}</td>
              <td>{e.location}</td>
              <td>{e.service}</td>
              <td>
                <select
                  value={e.status}
                  onChange={(ev) =>
                    updateStatus(e.id, ev.target.value)
                  }
                >
                  <option value="New">New</option>
                  <option value="Contacted">Contacted</option>
                  <option value="Completed">Completed</option>
                </select>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default Dashboard;
